Two parallel flows: keep the blink loop running, plus an analog subscription that drives a servo.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'
import { ConduytServo } from 'conduyt-js/modules/servo'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

await device.pin(13).mode('output')
const servo = new ConduytServo(device)
await servo.attach(9)

;(async () => {
  let on = 0
  while (true) {
    on ^= 1
    await device.pin(13).write(on)
    await new Promise(r => setTimeout(r, 500))
  }
})()

for await (const raw of device.pin('A0').subscribe({ intervalMs: 50 })) {
  await servo.write(Math.round((raw / 1023) * 180))
}
```

Add the ConduytDHT module and a setInterval. The blink and servo flows keep running.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'
import { ConduytServo } from 'conduyt-js/modules/servo'
import { ConduytDHT } from 'conduyt-js/modules/dht'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

await device.pin(13).mode('output')

const servo = new ConduytServo(device)
await servo.attach(9)

const dht = new ConduytDHT(device)
await dht.begin(4, 'DHT22')

;(async () => {
  let on = 0
  while (true) {
    on ^= 1
    await device.pin(13).write(on)
    await new Promise(r => setTimeout(r, 500))
  }
})()

setInterval(async () => {
  const { tempC, rh } = await dht.read()
  console.log('T=', tempC.toFixed(1), 'RH=', rh.toFixed(1))
}, 2000)

for await (const raw of device.pin('A0').subscribe({ intervalMs: 50 })) {
  await servo.write(Math.round((raw / 1023) * 180))
}
```

`navigator.serial.requestPort()` requires a user gesture; tie the connect to a click.

```ts
import { ConduytDevice } from 'conduyt-js'
import { WebSerialTransport } from 'conduyt-js/transports/web-serial'

document.querySelector<HTMLButtonElement>('#connect')!.addEventListener('click', async () => {
  const port = await navigator.serial.requestPort()
  const device = await ConduytDevice.connect(new WebSerialTransport({ port, baudRate: 115200 }))
  console.log('connected')
})
```

```ts
import { ConduytDevice } from 'conduyt-js'
import { WebSerialTransport } from 'conduyt-js/transports/web-serial'
import { ConduytNeoPixel } from 'conduyt-js/modules/neopixel'

document.querySelector<HTMLButtonElement>('#connect')!.addEventListener('click', async () => {
  const port = await navigator.serial.requestPort()
  const device = await ConduytDevice.connect(new WebSerialTransport({ port, baudRate: 115200 }))

  const strip = new ConduytNeoPixel(device)
  await strip.begin(5, 12)
  await strip.setBrightness(40)
  await strip.fill(0, 255, 0)
  await strip.show()
})
```

A simple three-way blend. The host subscribes to A0 and updates the strip on every sample.

```ts
import { ConduytDevice } from 'conduyt-js'
import { WebSerialTransport } from 'conduyt-js/transports/web-serial'
import { ConduytNeoPixel } from 'conduyt-js/modules/neopixel'

document.querySelector<HTMLButtonElement>('#connect')!.addEventListener('click', async () => {
  const port = await navigator.serial.requestPort()
  const device = await ConduytDevice.connect(new WebSerialTransport({ port, baudRate: 115200 }))

  const strip = new ConduytNeoPixel(device)
  await strip.begin(5, 12)
  await strip.setBrightness(40)

  for await (const raw of device.pin('A0').subscribe({ intervalMs: 50 })) {
    const t = raw / 1023
    let r = 0, g = 0, b = 0
    if (t < 0.5) { const k = t * 2; r = (1 - k) * 255; g = k * 255 }
    else         { const k = (t - 0.5) * 2; g = (1 - k) * 255; b = k * 255 }
    await strip.fill(Math.round(r), Math.round(g), Math.round(b))
    await strip.show()
  }
})
```

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

await device.pin(25).mode('output')
await device.pin(25).write(1)
await device.pin(15).mode('pwm')

while (true) {
  for (let d = 0; d <= 255; d += 4) {
    await device.pin(15).write(d)
    await new Promise(r => setTimeout(r, 8))
  }
  for (let d = 255; d >= 0; d -= 4) {
    await device.pin(15).write(d)
    await new Promise(r => setTimeout(r, 8))
  }
}
```

